var t={slug:"resume-site",title:"Resume Site",subtitle:"An interactive portfolio that is also the proof of work",role:"Designer, developer, and deploy owner",timeframe:"2024 \u2014 Present",tags:["Angular","WebGL","Canvas","Firebase","GitHub Pages"],heroImage:"case-studies/resume-site-hero.jpg",externalLinks:[{label:"View source on GitHub",url:"https://github.com/Upserge/Coding-Project-Files/tree/master/source/repos/cs-projects/ResumeSite"},{label:"Live site",url:"https://upserge.github.io/Jason.io/"}],summary:"A single-page Angular portfolio that doubles as a technical demo: WebGL hero shader, full-viewport canvas game, Firestore leaderboard, keyboard-driven navigation, and a one-command deploy pipeline to GitHub Pages.",metrics:[{label:"Stack",value:"Angular 21"},{label:"Game systems",value:"15 upgrades"},{label:"Unit tests",value:"80+ specs"}],sections:[{id:"problem",title:"Problem",body:["A static PDF r\xE9sum\xE9 cannot show how I think about systems, performance, or player-facing quality.","I wanted a home base that feels intentional for engineering recruiters: readable content up front, with craft demonstrated in the browser itself."]},{id:"approach",title:"Approach",body:["Built as a standalone Angular SPA with a canvas particle game running behind the r\xE9sum\xE9, wired to Firestore for persistent leaderboard scores.","Layered a WebGL hero shader, scroll-driven reveals, magnetic interactions, and focus-mode opacity tiers so the game and r\xE9sum\xE9 coexist without fighting for attention.","Added a deploy script that commits source to the monorepo, builds with the correct GitHub Pages base href, and publishes dist assets plus a 404 SPA fallback."]},{id:"impact",title:"Impact",body:["The site is both portfolio and artifact: visitors can read the r\xE9sum\xE9, play the game, and inspect the implementation on GitHub.","Phase 1 introduces on-site case studies so project proof lives on the domain instead of only linking out to repos."]},{id:"learnings",title:"Learnings",body:["Performance work (spatial grids, capped DPR, tab visibility pauses) matters as much as visual polish when a game loop runs behind content.","Deploy ergonomics are part of the product: if shipping is painful, the site will not stay current."]}]};var a={slug:"riot-valorant",title:"VALORANT Premier & Competitive Quality",subtitle:"Shipping ranked experiences where millions of players feel every defect",role:"Quality Owner \u2014 Premier (0\u21921) \xB7 Quality Lead \u2014 Competitive",timeframe:"Riot Games \xB7 2020 \u2014 Present",tags:["Test strategy","Automation","Global launch","Offshore leadership"],heroImage:"case-studies/valorant-premier-hero.webp",externalLinks:[{label:"LinkedIn",url:"https://linkedin.com/in/jasoncsalas"}],summary:"Led quality for VALORANT Competitive during a period of massive scope growth, then took Premier from zero to a global launch now live across 20 regional zones spanning the Americas, EMEA, and APAC.",metrics:[{label:"Premier zones",value:"20 regions"},{label:"Competitive QA lead",value:"2.5 years"},{label:"Premier ownership",value:"0\u21921 \xB7 ~4 yrs"},{label:"DDE/DRE coverage",value:"80%+"}],sections:[{id:"context",title:"Context",body:["VALORANT Competitive carries enormous scope: ranked integrity, feature cadence, and player trust at a scale where small defects become community-facing incidents overnight.","I spent two and a half years as Quality Lead for Competitive before the area split into three separate teams \u2014 a reflection of how much surface area the mode required.","Today I own quality for Premier end-to-end. I took Premier from 0\u21921 as the sole Quality Owner and have held that role for nearly four years."],figures:[{src:"case-studies/valorant-premier-hero.webp",alt:"VALORANT Premier press art"}]},{id:"launch",title:"Premier at global scale",body:["VALORANT Premier launched and is available in 20 regional zones, covering players across the Americas, EMEA (Europe, Middle East, and Africa), and APAC.","Launch quality required coordinating validation across regions, release cadences, and live-service expectations \u2014 not a single-ship milestone but an ongoing operational program."]},{id:"approach",title:"Approach",body:["Designed the overall test strategy for Premier launch and continued live support, balancing manual exploration with automation that protects high-risk paths.","Maintained rolling 80%+ DDE/DRE coverage to keep defect detection and removal effectiveness visible to the team.","Led multiple offshore testing teams, aligning execution models, communication rhythms, and quality bars across time zones.","Continuously evaluated and implemented new testing tools \u2014 automated and otherwise \u2014 to keep pace with feature velocity without sacrificing signal quality."]},{id:"impact",title:"Impact",body:["Premier moved from concept to a globally available competitive program with quality ownership centralized through its most formative years.","Competitive quality leadership scaled through team splits without losing continuity on player-facing risk \u2014 the org grew because the problem space demanded it.","The through-line for my engineering work today: design systems where failure is visible early, coverage is measurable, and shipping standards match what players expect at scale."]}]};var i=[t,a],r=new Map(i.map(e=>[e.slug,e]));function d(){return i}function c(e){return r.get(e)}export{d as a,c as b};
